const item = $input.first();
const body = item.json.body;
return [{ json: { org_id: body.org_id } }];

const { Client } = require('pg');
const item = $input.first().json;
const client = new Client({ host: $env.APP_PG_HOST || 'db', port: parseInt($env.APP_PG_PORT || '5432'), user: $env.APP_PG_USER, password: $env.APP_PG_PASSWORD, database: ($env.APP_PG_DATABASE || 'ragkb_app') });
await client.connect();
try {
  const result = await client.query(
    'SELECT id, title, status, total_cost, created_at FROM "Estimate" WHERE organization_id = $1 ORDER BY created_at DESC LIMIT 20',
    [item.org_id]
  );
  return [{ json: { estimates: result.rows.map(r => ({ id: r.id, title: r.title, status: r.status, total_cost: r.total_cost ? parseFloat(r.total_cost) : null, created_at: r.created_at.toISOString() })) } }];
} finally {
  await client.end();
}
